tinymce.Resource.add("tinymce.html-i18n.help-keynav.he_IL",`<h1>\u05D4\u05EA\u05D7\u05DC \u05E0\u05D9\u05D5\u05D5\u05D8 \u05D1\u05DE\u05E7\u05DC\u05D3\u05EA</h1>

<dl>
  <dt>\u05D4\u05EA\u05DE\u05E7\u05D3 \u05D1\u05E9\u05D5\u05E8\u05EA \u05D4\u05EA\u05E4\u05E8\u05D9\u05D8\u05D9\u05DD</dt>
  <dd>Windows \u05D0\u05D5 Linux:\u200F Alt+F9</dd>
  <dd>macOS: &#x2325;F9</dd>
  <dt>\u05D4\u05E2\u05D1\u05E8 \u05DE\u05D9\u05E7\u05D5\u05D3 \u05DC\u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD</dt>
  <dd>Windows \u05D0\u05D5 Linux:\u200F Alt+F10</dd>
  <dd>macOS: &#x2325;F10</dd>
  <dt>\u05D4\u05E2\u05D1\u05E8 \u05DE\u05D9\u05E7\u05D5\u05D3 \u05DC\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4</dt>
  <dd>Windows \u05D0\u05D5 Linux:\u200F Alt+F11</dd>
  <dd>macOS: &#x2325;F11</dd>
  <dt>\u05D4\u05E2\u05D1\u05E8 \u05DE\u05D9\u05E7\u05D5\u05D3 \u05DC\u05D4\u05D5\u05D3\u05E2\u05D4</dt>
  <dd>Windows \u05D0\u05D5 Linux:\u200F Alt+F12</dd>
  <dd>macOS: &#x2325;F12</dd>
  <dt>\u05D4\u05E2\u05D1\u05E8 \u05DE\u05D9\u05E7\u05D5\u05D3 \u05DC\u05E1\u05E8\u05D2\u05DC \u05DB\u05DC\u05D9\u05DD \u05D4\u05E7\u05E9\u05E8\u05D9</dt>
  <dd>Windows\u200F, Linux \u05D0\u05D5 macOS:\u200F Ctrl+F9</dd>
</dl>

<p>\u05D4\u05E0\u05D9\u05D5\u05D5\u05D8 \u05D9\u05EA\u05D7\u05D9\u05DC \u05D1\u05E8\u05DB\u05D9\u05D1 \u05D4\u05E8\u05D0\u05E9\u05D5\u05DF \u05D1\u05DE\u05E9\u05DA, \u05E9\u05D9\u05D5\u05D3\u05D2\u05E9 \u05D0\u05D5 \u05E9\u05D9\u05D4\u05D9\u05D4 \u05DE\u05EA\u05D7\u05EA\u05D9\u05D5 \u05E7\u05D5 \u05EA\u05D7\u05EA\u05D5\u05DF \u05D1\u05DE\u05E7\u05E8\u05D4 \u05E9\u05DC \u05D4\u05E4\u05E8\u05D9\u05D8 \u05D4\u05E8\u05D0\u05E9\u05D5\u05DF
  \u05D4\u05E0\u05EA\u05D9\u05D1 \u05E9\u05DC \u05E8\u05DB\u05D9\u05D1 \u05D4\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4.</p>

<h1>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05DE\u05E7\u05D8\u05E2\u05D9\u05DD \u05D1\u05DE\u05E1\u05DA</h1>

<p>\u05DB\u05D3\u05D9 \u05DC\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05D4\u05DE\u05E7\u05D8\u05E2\u05D9\u05DD \u05D1\u05DE\u05E1\u05DA, \u05D4\u05E7\u05E9 <strong>Tab</strong>.</p>

<p>\u05DB\u05D3\u05D9 \u05DC\u05E2\u05D1\u05D5\u05E8 \u05DC\u05DE\u05E7\u05D8\u05E2 \u05D4\u05E7\u05D5\u05D3\u05DD \u05D1\u05DE\u05E1\u05DA, \u05D4\u05E7\u05E9 <strong>Shift+Tab</strong>.</p>

<p>\u05D4\u05E1\u05D3\u05E8 \u05DE\u05D1\u05D7\u05D9\u05E0\u05EA \u05DE\u05E7\u05E9 <strong>Tab</strong> \u05E9\u05DC \u05D4\u05E8\u05DB\u05D9\u05D1\u05D9\u05DD \u05D1\u05DE\u05E1\u05DA:</p>

<ol>
  <li>\u05E9\u05D5\u05E8\u05EA \u05D4\u05EA\u05E4\u05E8\u05D9\u05D8\u05D9\u05DD</li>
  <li>\u05DB\u05DC \u05E7\u05D1\u05D5\u05E6\u05D4 \u05D1\u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD</li>
  <li>\u05D4\u05E1\u05E8\u05D2\u05DC \u05D4\u05E6\u05D9\u05D3\u05D9</li>
  <li>\u05E0\u05EA\u05D9\u05D1 \u05E9\u05DC \u05E8\u05DB\u05D9\u05D1 \u05D1\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4</li>
  <li>\u05DC\u05D7\u05E6\u05DF \u05DC\u05E1\u05E4\u05D9\u05E8\u05EA \u05DE\u05D9\u05DC\u05D9\u05DD \u05D1\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4</li>
  <li>\u05E7\u05D9\u05E9\u05D5\u05E8 \u05E9\u05DC \u05D4\u05DE\u05D5\u05EA\u05D2 \u05D1\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4</li>
  <li>\u05D9\u05D3\u05D9\u05EA \u05DC\u05E9\u05D9\u05E0\u05D5\u05D9 \u05D2\u05D5\u05D3\u05DC \u05E2\u05D1\u05D5\u05E8 \u05D4\u05E2\u05D5\u05E8\u05DA \u05D1\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4</li>
</ol>

<p>\u05D0\u05DD \u05E8\u05DB\u05D9\u05D1 \u05DB\u05DC\u05E9\u05D4\u05D5 \u05D1\u05DE\u05E1\u05DA \u05DC\u05D0 \u05DE\u05D5\u05E4\u05D9\u05E2, \u05D4\u05DE\u05E2\u05E8\u05DB\u05EA \u05EA\u05D3\u05DC\u05D2 \u05E2\u05DC\u05D9\u05D5.</p>

<p>\u05D0\u05DD \u05D1\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4 \u05D9\u05E9 \u05DE\u05D9\u05E7\u05D5\u05D3 \u05E9\u05DC \u05E0\u05D9\u05D5\u05D5\u05D8 \u05D1\u05DE\u05E7\u05DC\u05D3\u05EA, \u05D5\u05DC\u05D0 \u05DE\u05D5\u05E4\u05D9\u05E2 \u05E1\u05E8\u05D2\u05DC \u05D1\u05E6\u05D3, \u05D9\u05E9 \u05DC\u05D4\u05E7\u05D9\u05E9 <strong>Shift+Tab</strong>
  \u05DE\u05E2\u05D1\u05D9\u05E8 \u05D0\u05EA \u05D4\u05DE\u05D9\u05E7\u05D5\u05D3 \u05DC\u05E7\u05D1\u05D5\u05E6\u05D4 \u05D4\u05E8\u05D0\u05E9\u05D5\u05E0\u05D4 \u05D1\u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD, \u05DC\u05D0 \u05D4\u05D0\u05D7\u05E8\u05D5\u05E0\u05D4.</p>

<h1>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05EA\u05D5\u05DA \u05DE\u05E7\u05D8\u05E2\u05D9\u05DD \u05D1\u05DE\u05E1\u05DA</h1>

<p>\u05DB\u05D3\u05D9 \u05DC\u05E2\u05D1\u05D5\u05E8 \u05DE\u05E8\u05DB\u05D9\u05D1 \u05D0\u05D7\u05D3 \u05DC\u05E8\u05DB\u05D9\u05D1 \u05D0\u05D7\u05E8 \u05D1\u05DE\u05E1\u05DA, \u05D4\u05E7\u05E9 \u05E2\u05DC \u05DE\u05E7\u05E9 <strong>\u05D4\u05D7\u05E5</strong> \u05D4\u05DE\u05EA\u05D0\u05D9\u05DD.</p>

<p>\u05DE\u05E7\u05E9\u05D9 \u05D4\u05D7\u05D9\u05E6\u05D9\u05DD <strong>\u05E9\u05DE\u05D0\u05DC\u05D4</strong> \u05D5<strong>\u05D9\u05DE\u05D9\u05E0\u05D4</strong></p>

<ul>
  <li>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05EA\u05E4\u05E8\u05D9\u05D8\u05D9\u05DD \u05D1\u05E9\u05D5\u05E8\u05EA \u05D4\u05EA\u05E4\u05E8\u05D9\u05D8\u05D9\u05DD.</li>
  <li>\u05E4\u05EA\u05D7 \u05EA\u05E4\u05E8\u05D9\u05D8 \u05DE\u05E9\u05E0\u05D9 \u05D1\u05EA\u05E4\u05E8\u05D9\u05D8.</li>
  <li>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05DC\u05D7\u05E6\u05E0\u05D9\u05DD \u05D1\u05E7\u05D1\u05D5\u05E6\u05D4 \u05D1\u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD.</li>
  <li>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05E4\u05E8\u05D9\u05D8\u05D9\u05DD \u05D1\u05E8\u05DB\u05D9\u05D1 \u05D1\u05DB\u05D5\u05EA\u05E8\u05EA \u05D4\u05EA\u05D7\u05EA\u05D5\u05E0\u05D4.</li>
</ul>

<p>\u05DE\u05E7\u05E9\u05D9 \u05D4\u05D7\u05D9\u05E6\u05D9\u05DD <strong>\u05DC\u05DE\u05D8\u05D4</strong> \u05D5<strong>\u05DC\u05DE\u05E2\u05DC\u05D4</strong></p>

<ul>
  <li>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05E4\u05E8\u05D9\u05D8\u05D9\u05DD \u05D1\u05EA\u05E4\u05E8\u05D9\u05D8.</li>
  <li>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05E4\u05E8\u05D9\u05D8\u05D9\u05DD \u05D1\u05D7\u05DC\u05D5\u05DF \u05D4\u05E7\u05D5\u05D1\u05E5 \u05E9\u05DC \u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD.</li>
</ul>

<p>\u05DE\u05E7\u05E9\u05D9 <strong>\u05D4\u05D7\u05E6\u05D9\u05DD</strong> \u05DE\u05E9\u05EA\u05E0\u05D9\u05DD \u05D1\u05EA\u05D5\u05DA \u05D4\u05DE\u05E7\u05D8\u05E2 \u05D1\u05DE\u05E1\u05DA \u05E9\u05E2\u05DC\u05D9\u05D5 \u05E0\u05DE\u05E6\u05D0 \u05D4\u05DE\u05D9\u05E7\u05D5\u05D3.</p>

<p>\u05DB\u05D3\u05D9 \u05DC\u05E1\u05D2\u05D5\u05E8 \u05EA\u05E4\u05E8\u05D9\u05D8 \u05E4\u05EA\u05D5\u05D7, \u05EA\u05E4\u05E8\u05D9\u05D8 \u05DE\u05E9\u05E0\u05D9 \u05E4\u05EA\u05D5\u05D7 \u05D0\u05D5 \u05D7\u05DC\u05D5\u05DF \u05E7\u05D5\u05E4\u05E5, \u05D4\u05E7\u05E9 \u05E2\u05DC <strong>Esc</strong>.</p>

<p>\u05D0\u05DD \u05D4\u05DE\u05D9\u05E7\u05D5\u05D3 \u05D4\u05D5\u05D0 \u05E2\u05DC \u05D4\u05D7\u05DC\u05E7 '\u05D4\u05E2\u05DC\u05D9\u05D5\u05DF' \u05E9\u05DC \u05DE\u05E7\u05D8\u05E2 \u05DE\u05E1\u05D5\u05D9\u05DD \u05D1\u05DE\u05E1\u05DA, \u05D4\u05E7\u05E9\u05D4 \u05E2\u05DC <strong>Esc</strong> \u05DE\u05D1\u05D9\u05D0\u05D4 \u05D2\u05DD \u05DC\u05D9\u05E6\u05D9\u05D0\u05D4
  \u05DE\u05D4\u05E0\u05D9\u05D5\u05D5\u05D8 \u05D1\u05DE\u05E7\u05DC\u05D3\u05EA \u05DC\u05D7\u05DC\u05D5\u05D8\u05D9\u05DF.</p>

<h1>\u05D4\u05E4\u05E2\u05DC \u05E4\u05E8\u05D9\u05D8 \u05D1\u05EA\u05E4\u05E8\u05D9\u05D8 \u05D0\u05D5 \u05DC\u05D7\u05E6\u05DF \u05D1\u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD</h1>

<p>\u05DB\u05D0\u05E9\u05E8 \u05D4\u05E4\u05E8\u05D9\u05D8 \u05D4\u05E8\u05E6\u05D5\u05D9 \u05D1\u05EA\u05E4\u05E8\u05D9\u05D8 \u05D0\u05D5 \u05D4\u05DC\u05D7\u05E6\u05DF \u05D1\u05E1\u05E8\u05D2\u05DC \u05D4\u05DB\u05DC\u05D9\u05DD \u05DE\u05D5\u05D3\u05D2\u05E9\u05D9\u05DD, \u05D4\u05E7\u05E9 \u05E2\u05DC <strong>Return</strong>, <strong>Enter</strong>,
  \u05D0\u05D5 \u05E2\u05DC <strong>\u05DE\u05E7\u05E9 \u05D4\u05E8\u05D5\u05D5\u05D7</strong> \u05DB\u05D3\u05D9 \u05DC\u05D4\u05E4\u05E2\u05D9\u05DC \u05D0\u05EA \u05D4\u05E4\u05E8\u05D9\u05D8.</p>

<h1>\u05E0\u05D9\u05D5\u05D5\u05D8 \u05D1\u05D7\u05DC\u05D5\u05E0\u05D5\u05EA \u05D3\u05D5-\u05E9\u05D9\u05D7 \u05D1\u05DC\u05D9 \u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D5\u05EA</h1>

<p>\u05D1\u05D7\u05DC\u05D5\u05E0\u05D5\u05EA \u05D3\u05D5-\u05E9\u05D9\u05D7 \u05D1\u05DC\u05D9 \u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D5\u05EA, \u05D4\u05E8\u05DB\u05D9\u05D1 \u05D4\u05D0\u05D9\u05E0\u05D8\u05E8\u05D0\u05E7\u05D8\u05D9\u05D1\u05D9 \u05D4\u05E8\u05D0\u05E9\u05D5\u05DF \u05DE\u05E7\u05D1\u05DC \u05D0\u05EA \u05D4\u05DE\u05D9\u05E7\u05D5\u05D3 \u05DB\u05D0\u05E9\u05E8 \u05D4\u05D7\u05DC\u05D5\u05DF \u05E0\u05E4\u05EA\u05D7.</p>

<p>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05E8\u05DB\u05D9\u05D1\u05D9\u05DD \u05D0\u05D9\u05E0\u05D8\u05E8\u05D0\u05E7\u05D8\u05D9\u05D1\u05D9\u05D9\u05DD \u05D1\u05D7\u05DC\u05D5\u05DF \u05E2\u05DC \u05D9\u05D3\u05D9 \u05D4\u05E7\u05E9\u05D4 \u05E2\u05DC <strong>Tab</strong> \u05D0\u05D5 <strong>Shift+Tab</strong>.</p>

<h1>\u05E0\u05D9\u05D5\u05D5\u05D8 \u05D1\u05D7\u05DC\u05D5\u05E0\u05D5\u05EA \u05D3\u05D5-\u05E9\u05D9\u05D7 \u05E2\u05DD \u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D5\u05EA</h1>

<p>\u05D1\u05D7\u05DC\u05D5\u05E0\u05D5\u05EA \u05D3\u05D5-\u05E9\u05D9\u05D7 \u05E2\u05DD \u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D5\u05EA, \u05D4\u05DC\u05D7\u05E6\u05DF \u05D4\u05E8\u05D0\u05E9\u05D5\u05DF \u05D1\u05EA\u05E4\u05E8\u05D9\u05D8 \u05DE\u05E7\u05D1\u05DC \u05D0\u05EA \u05D4\u05DE\u05D9\u05E7\u05D5\u05D3 \u05DB\u05D0\u05E9\u05E8 \u05D4\u05D7\u05DC\u05D5\u05DF \u05E0\u05E4\u05EA\u05D7.</p>

<p>\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05E8\u05DB\u05D9\u05D1\u05D9\u05DD \u05D0\u05D9\u05E0\u05D8\u05E8\u05D0\u05E7\u05D8\u05D9\u05D1\u05D9\u05D9\u05DD \u05D1\u05D7\u05DC\u05D5\u05DF \u05E2\u05DC \u05D9\u05D3\u05D9 \u05D4\u05E7\u05E9\u05D4 \u05E2\u05DC <strong>Tab</strong> \u05D0\u05D5
  <strong>Shift+Tab</strong>.</p>

<p>\u05E2\u05D1\u05D5\u05E8 \u05DC\u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D4 \u05D0\u05D7\u05E8\u05EA \u05D1\u05D7\u05DC\u05D5\u05DF \u05E2\u05DC \u05D9\u05D3\u05D9 \u05D4\u05E2\u05D1\u05E8\u05EA \u05D4\u05DE\u05D9\u05E7\u05D5\u05D3 \u05DC\u05EA\u05E4\u05E8\u05D9\u05D8 \u05D4\u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D5\u05EA \u05D5\u05D4\u05E7\u05E9\u05D4 \u05E2\u05DC <strong>\u05D4\u05D7\u05E5</strong>\u05D4\u05DE\u05EA\u05D0\u05D9\u05DD
  \u05DB\u05D3\u05D9 \u05DC\u05E2\u05D1\u05D5\u05E8 \u05D1\u05D9\u05DF \u05D4\u05DB\u05E8\u05D8\u05D9\u05E1\u05D9\u05D5\u05EA \u05D4\u05D6\u05DE\u05D9\u05E0\u05D5\u05EA.</p>
`);
